SELECT id, groupName AS title
FROM torrents
ORDER BY id;

SELECT DISTINCT t.groupName AS title
FROM torrents t
JOIN tags g ON g.id = t.id;

SELECT groupName, artist, totalSnatched
FROM torrents
WHERE totalSnatched = (SELECT MIN(totalSnatched) FROM torrents);

SELECT t.*
FROM torrents t
WHERE t.totalSnatched = (SELECT MAX(totalSnatched) FROM torrents);

SELECT groupYear AS release_year, groupName AS release_title, totalSnatched AS downloads
FROM torrents
ORDER BY release_year, downloads DESC;

SELECT Datetime, Country, League, HomeTeam, AwayTeam, FTHG, FTAG
FROM football_data
