SELECT Season, Div, HomeTeam, AwayTeam
FROM football_data
WHERE FTR = 'D' AND FTHG = 0 AND FTAG = 0;

SELECT Country, League, HomeTeam || ' vs ' || AwayTeam AS Match, Datetime
FROM football_data
WHERE COALESCE(FTHG, 0) = 0 AND COALESCE(FTAG, 0) = 0;

SELECT YEAR, DATETIME, COUNTRY, COMPETION, MATCH, DRAW_CLOSING
FROM betfront
WHERE MATCH LIKE '%VfB Stuttgart%';

SELECT Season, Datetime, Country, League, HomeTeam, AwayTeam, PSD AS draw_odds
FROM football_data
WHERE HomeTeam = 'VfB Stuttgart' OR AwayTeam = 'VfB Stuttgart';

SELECT Season, Datetime, Country, League, HomeTeam, AwayTeam, B365D AS draw_odds
FROM football_data
WHERE HomeTeam = 'VfB Stuttgart' OR AwayTeam = 'VfB Stuttgart';

SELECT YEAR, DATETIME, MATCH, DRAW_OPENING, DRAW_CLOSING
FROM betfront
WHERE MATCH LIKE '%VfB Stuttgart%';

SELECT Season, Datetime, HomeTeam, AwayTeam, PSD, B365D, LBD, BWD
FROM football_data
WHERE HomeTeam = 'VfB Stuttgart' OR AwayTeam = 'VfB Stuttgart';

SELECT HomeTeam, AwayTeam
FROM football_data
