SELECT MATCH, DATETIME, DRAW_OPENING
FROM betfront
WHERE DRAW_OPENING > 3;

SELECT Datetime, League, HomeTeam, AwayTeam, FTHG, FTAG
FROM football_data
WHERE Country = 'Spain' AND FTR = 'A';

SELECT Datetime, HomeTeam, AwayTeam, FTHG, FTAG
FROM football_data
WHERE Country = 'Spain' AND FTAG > FTHG;

SELECT Datetime, HomeTeam || ' vs ' || AwayTeam AS Match
FROM football_data
WHERE Country = 'Spain' AND FTR = 'A';

SELECT YEAR, DATETIME, COMPETION, MATCH
FROM betfront
WHERE COUNTRY = 'Spain' AND MATCH LIKE '%-%';

SELECT Datetime, Season, Country, League, HomeTeam, AwayTeam, PSH AS pinnacle_win_odds
FROM football_data
WHERE HomeTeam = 'Arsenal' AND FTR = 'H';

SELECT Datetime, Season, Country, League, HomeTeam, AwayTeam, PSA AS pinnacle_win_odds
FROM football_data
WHERE AwayTeam = 'Arsenal' AND FTR = 'A';

SELECT Datetime, Season, Country, League, HomeTeam, AwayTeam, PSH, PSD, PSA
FROM football_data
