SELECT DISTINCT STATE
FROM Fires
WHERE FIRE_SIZE = (SELECT MAX(FIRE_SIZE) FROM Fires WHERE FIRE_SIZE IS NOT NULL);

SELECT AVG(CAST(CONT_DOY AS INTEGER) - DISCOVERY_DOY) AS avg_days_to_control
FROM Fires
WHERE CONT_DOY IS NOT NULL AND DISCOVERY_DOY IS NOT NULL;

SELECT AVG(julianday(CONT_DATE) - julianday(date(DISCOVERY_DATE))) AS avg_days_to_control
FROM Fires
WHERE CONT_DATE IS NOT NULL AND DISCOVERY_DATE IS NOT NULL;

SELECT AVG(CAST(CONT_DATE AS REAL) - DISCOVERY_DATE) AS avg_days_to_control
FROM Fires
WHERE CONT_DATE IS NOT NULL AND DISCOVERY_DATE IS NOT NULL;

SELECT COUNT(*) AS crime_count
FROM GreaterManchesterCrime
WHERE Location = 'Eden Street';

SELECT COUNT(*) AS crime_count
FROM GreaterManchesterCrime
WHERE Location LIKE '%Eden Street%';

SELECT COUNT(DISTINCT CrimeID) AS crime_count
FROM GreaterManchesterCrime
WHERE Location = 'Eden Street';

SELECT AVG(CAST(death_year AS INTEGER) - CAST(birth_year AS INTEGER)) AS avg_lifespan_years
FROM player
WHERE death_year IS NOT NULL AND birth_year IS NOT NULL;

SELECT AVG(death_year - birth_year) AS avg_lifespan_years
FROM player
WHERE death_year IS NOT NULL AND birth_year IS NOT NULL;

SELECT AVG(
  (julianday(
     printf('%04d-%02d-%02d', CAST(death_year AS INTEGER), COALESCE(CAST(death_month AS INTEGER), 1), COALESCE(CAST(death_day AS INTEGER), 1))
   ) - julianday(
     printf('%04d-%02d-%02d', CAST(birth_year AS INTEGER), COALESCE(CAST(birth_month AS INTEGER), 1), COALESCE(CAST(birth_day AS INTEGER), 1))
   )) / 365.25
) AS avg_lifespan_years
FROM player
WHERE birth_year IS NOT NULL AND death_year IS NOT NULL;

SELECT AVG(
  (julianday(COALESCE(
      printf('%04d-%02d-%02d', CAST(death_year AS INTEGER), COALESCE(CAST(death_month AS INTEGER), 1), COALESCE(CAST(death_day AS INTEGER), 1)),
      date('now')
   )) - julianday(
      printf('%04d-%02d-%02d', CAST(birth_year AS INTEGER), COALESCE(CAST(birth_month AS INTEGER), 1), COALESCE(CAST(birth_day AS INTEGER), 1))
   )) / 365.25
) AS avg_age_years
FROM player
WHERE birth_year IS NOT NULL;

SELECT AVG(CAST(death_year AS INTEGER)) - AVG(CAST(birth_year AS INTEGER)) AS avg_lifespan_years
FROM player
WHERE death_year IS NOT NULL AND birth_year IS NOT NULL;

SELECT AVG(
         (julianday('now') - julianday(
            CAST(birth_year AS INTEGER) || '-' || printf('%02d', CAST(birth_month AS INTEGER)) || '-' || printf('%02d', CAST(birth_day AS INTEGER))
         )) / 365.25
       ) AS avg_age
FROM player
WHERE birth_country = 'USA'
  AND birth_year IS NOT NULL AND birth_month IS NOT NULL AND birth_day IS NOT NULL;

SELECT p.player_id, p.name_first, p.name_last, p.birth_year, p.birth_month, p.birth_day
FROM player p
ORDER BY DATE(
  printf('%04d-%02d-%02d', CAST(p.birth_year AS INT), CAST(COALESCE(NULLIF(p.birth_month,''), '1') AS INT), CAST(COALESCE(NULLIF(p.birth_day,''), '1') AS INT))
) DESC
LIMIT 1;

SELECT AVG(player_avg_salary) AS avg_pay
FROM (
  SELECT s.player_id, AVG(s.salary) AS player_avg_salary
  FROM salary s
  WHERE EXISTS (
    SELECT 1 FROM hall_of_fame h
    WHERE h.player_id = s.player_id AND h.inducted = 'Y'
  )
  GROUP BY s.player_id
) t;

